import React, { useState } from 'react';
import { X, User, GraduationCap } from 'lucide-react';
import useAuthStore from '../store/authStore';

const LoginModal = ({ onClose }) => {
  const [selectedRole, setSelectedRole] = useState('student');
  const { login } = useAuthStore();

  const handleLogin = () => {
    const userData = {
      id: Date.now(),
      name: selectedRole === 'student' ? 'Student User' : 'Instructor User',
      email: `${selectedRole}@example.com`,
      role: selectedRole,
      avatar: null
    };

    login(userData);
    onClose();
  };

  return (
    <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
      <div className="bg-white rounded-2xl max-w-md w-full shadow-2xl">
        <div className="p-6 border-b border-gray-200">
          <div className="flex justify-between items-center">
            <h2 className="text-xl font-bold text-gray-900">Choose Your Role</h2>
            <button onClick={onClose} className="p-2 hover:bg-gray-100 rounded-lg">
              <X className="w-5 h-5" />
            </button>
          </div>
        </div>

        <div className="p-6">
          <div className="space-y-4 mb-6">
            <button
              onClick={() => setSelectedRole('student')}
              className={`w-full p-4 rounded-xl border-2 transition-all ${
                selectedRole === 'student'
                  ? 'border-blue-500 bg-blue-50'
                  : 'border-gray-200 hover:border-gray-300'
              }`}
            >
              <div className="flex items-center space-x-3">
                <div className={`w-12 h-12 rounded-full flex items-center justify-center ${
                  selectedRole === 'student' ? 'bg-blue-500' : 'bg-gray-400'
                }`}>
                  <User className="w-6 h-6 text-white" />
                </div>
                <div className="text-left">
                  <h3 className="font-semibold text-gray-900">Student</h3>
                  <p className="text-sm text-gray-600">Browse and enroll in courses</p>
                </div>
              </div>
            </button>

            <button
              onClick={() => setSelectedRole('instructor')}
              className={`w-full p-4 rounded-xl border-2 transition-all ${
                selectedRole === 'instructor'
                  ? 'border-purple-500 bg-purple-50'
                  : 'border-gray-200 hover:border-gray-300'
              }`}
            >
              <div className="flex items-center space-x-3">
                <div className={`w-12 h-12 rounded-full flex items-center justify-center ${
                  selectedRole === 'instructor' ? 'bg-purple-500' : 'bg-gray-400'
                }`}>
                  <GraduationCap className="w-6 h-6 text-white" />
                </div>
                <div className="text-left">
                  <h3 className="font-semibold text-gray-900">Instructor</h3>
                  <p className="text-sm text-gray-600">Create and manage courses</p>
                </div>
              </div>
            </button>
          </div>

          <button
            onClick={handleLogin}
            className={`w-full py-3 rounded-lg font-semibold text-white transition-colors ${
              selectedRole === 'student'
                ? 'bg-blue-600 hover:bg-blue-700'
                : 'bg-purple-600 hover:bg-purple-700'
            }`}
          >
            Continue as {selectedRole === 'student' ? 'Student' : 'Instructor'}
          </button>
        </div>
      </div>
    </div>
  );
};

export default LoginModal;
